function chooseControl(symptom) {
  const normalized = symptom.toLowerCase();
  if (normalized.includes("repeated") || normalized.includes("same prompt")) return "cache";
  if (normalized.includes("minutes") || normalized.includes("long")) return "queue";
  if (normalized.includes("500") || normalized.includes("per minute") || normalized.includes("many requests")) return "rate-limit";
  return "monitor";
}
